from enum import Enum

class CommsApprovalState(Enum):
    DRAFT    = "draft"
    PENDING  = "pending_ic_approval"
    APPROVED = "approved"
    PUBLISHED = "published"

class CommsMessage:
    def __init__(self, incident_id: str, audience: str, body: str):
        self.incident_id = incident_id
        self.audience = audience        # "status_page" | "enterprise" | "exec"
        self.body = body
        self.state = CommsApprovalState.DRAFT
        self.approved_by: str | None = None

    def submit_for_approval(self, requester: str) -> None:
        if self.state != CommsApprovalState.DRAFT:
            raise ValueError(f"Cannot submit; current state is {self.state}")
        self.state = CommsApprovalState.PENDING
        notify_ic(self.incident_id, requester, self)  # noqa: F821

    def approve(self, ic_user_id: str) -> None:
        if self.state != CommsApprovalState.PENDING:
            raise ValueError(f"Cannot approve; current state is {self.state}")
        self.approved_by = ic_user_id
        self.state = CommsApprovalState.APPROVED

    def publish(self) -> None:
        if self.state != CommsApprovalState.APPROVED:
            raise PermissionError("Cannot publish without IC approval")
        _do_publish(self)           # noqa: F821
        self.state = CommsApprovalState.PUBLISHED

